@Composable fun LoginScreen( uiState: LoginUiState, onRoleSelected: (UserRole) -> Unit, onEmailChanged: (String) -> Unit, onPasswordChanged: (String) -> Unit, onRememberFor30DaysChanged: (Boolean) -> Unit, onForgotPasswordClick: () -> Unit, onRequestAccessClick: () -> Unit, onLoginClick: () -> Unit ) { val context = LocalContext.current val background = Color(0xFFF2F4F8) val cardBackground = Color.White val primaryBlue = Color(0xFF001F4E) val sectionLabel = Color(0xFF475569) val inputBackground = Color(0xFFF3F4F6) val mutedText = Color(0xFF6B7280) var isPasswordVisible by remember { mutableStateOf(false) }
LaunchedEffect(uiState.errorMessage) { if (uiState.errorMessage.equals("Wrong credentials", ignoreCase = true)) { Toast.makeText(context, "Wrong credentials", Toast.LENGTH_SHORT).show() } }
Column( modifier = Modifier .fillMaxSize() .background(background) .verticalScroll(rememberScrollState()) .padding(horizontal = 22.dp, vertical = 20.dp), horizontalAlignment = Alignment.CenterHorizontally ) { Column( modifier = Modifier .fillMaxWidth() .background(cardBackground, RoundedCornerShape(32.dp)) .padding(horizontal = 24.dp, vertical = 32.dp) ) { Column( modifier = Modifier.fillMaxWidth(), horizontalAlignment = Alignment.CenterHorizontally ) { Box( modifier = Modifier .background(Color(0xFFEAF2FF), RoundedCornerShape(12.dp)) .padding(horizontal = 10.dp, vertical = 8.dp) ) { Icon( imageVector = Icons.AutoMirrored.Outlined.MenuBook, contentDescription = "App icon", tint = primaryBlue ) }
Spacer(modifier = Modifier.height(8.dp))
Text( text = "MyCampus", color = primaryBlue, style = AppTextStyles.sectionLabel, fontSize = 24.sp )
Spacer(modifier = Modifier.height(16.dp)) }
Text( text = "Welcome Back", style = AppTextStyles.screenTitle, color = primaryBlue, fontWeight = FontWeight.Bold, modifier = Modifier.fillMaxWidth(), textAlign = TextAlign.Center )
Spacer(modifier = Modifier.height(10.dp))
Text( text = "Sign in to continue your research\njourney", style = AppTextStyles.screenSubtitle, color = mutedText, modifier = Modifier.fillMaxWidth(), textAlign = TextAlign.Center )
Spacer(modifier = Modifier.height(32.dp))
Text( text = "I AM A", color = sectionLabel, fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp ) Spacer(modifier = Modifier.height(14.dp))
Row(horizontalArrangement = Arrangement.spacedBy(16.dp)) { RoleButton( title = "Student", isSelected = uiState.selectedRole == UserRole.STUDENT, icon = { Icon( imageVector = Icons.Outlined.School, contentDescription = null, tint = primaryBlue, modifier = Modifier.size(28.dp) ) }, onClick = { onRoleSelected(UserRole.STUDENT) }, modifier = Modifier.weight(1f), primaryBlue = primaryBlue )
RoleButton( title = "Professor", isSelected = uiState.selectedRole == UserRole.PROFESSOR, icon = { Icon( imageVector = Icons.Outlined.Badge, contentDescription = null, tint = primaryBlue, modifier = Modifier.size(28.dp) ) }, onClick = { onRoleSelected(UserRole.PROFESSOR) }, modifier = Modifier.weight(1f), primaryBlue = primaryBlue ) }
Spacer(modifier = Modifier.height(24.dp))
InputField( value = uiState.email, onValueChange = onEmailChanged, placeholder = "University Email", leadingIcon = { Icon( imageVector = Icons.Outlined.AlternateEmail, contentDescription = null, tint = mutedText ) }, keyboardType = KeyboardType.Email, visualTransformation = null, background = inputBackground )
if (uiState.emailError != null) { Spacer(modifier = Modifier.height(6.dp)) Text( text = uiState.emailError, color = Color(0xFFB42318), style = AppTextStyles.body ) }
Spacer(modifier = Modifier.height(16.dp))
InputField( value = uiState.password, onValueChange = onPasswordChanged, placeholder = "Password", leadingIcon = { Icon( imageVector = Icons.Outlined.Lock, contentDescription = null, tint = mutedText ) }, keyboardType = KeyboardType.Password, visualTransformation = if (isPasswordVisible) VisualTransformation.None else PasswordVisualTransformation(), trailingIcon = { IconButton(onClick = { isPasswordVisible = !isPasswordVisible }) { Icon( imageVector = if (isPasswordVisible) Icons.Outlined.VisibilityOff else Icons.Outlined.Visibility, contentDescription = if (isPasswordVisible) "Hide password" else "Show password", tint = mutedText ) } }, background = inputBackground )
Spacer(modifier = Modifier.height(16.dp))
Row( modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.End ) { Text( text = "Forgot Password?", color = Color(0xFF0265DC), fontSize = 13.sp, fontWeight = FontWeight.SemiBold, modifier = Modifier.clickable(onClick = onForgotPasswordClick) ) }
Spacer(modifier = Modifier.height(24.dp))
Button( onClick = onLoginClick, enabled = !uiState.isAuthenticating, colors = ButtonDefaults.buttonColors(containerColor = primaryBlue), modifier = Modifier .fillMaxWidth() .height(64.dp), shape = RoundedCornerShape(14.dp) ) { Row( verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.Center ) { Text( text = if (uiState.isAuthenticating) "Authenticating..." else "Enter the Vault", style = AppTextStyles.primaryButton, color = Color.White, fontWeight = FontWeight.SemiBold ) Spacer(modifier = Modifier.width(10.dp)) Icon( imageVector = Icons.AutoMirrored.Outlined.ArrowForward, contentDescription = null, tint = Color.White ) } }
if (uiState.errorMessage != null) { Spacer(modifier = Modifier.height(8.dp)) Text( text = uiState.errorMessage, color = Color(0xFFB42318), style = MaterialTheme.typography.bodyMedium, modifier = Modifier.fillMaxWidth(), textAlign = TextAlign.Center ) }
Spacer(modifier = Modifier.height(32.dp))
Row( modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.Center ) { Text( text = "New to the institution? ", color = Color(0xFF475569), fontSize = 13.sp ) Text( text = "Create Account", color = primaryBlue, fontSize = 13.sp, fontWeight = FontWeight.Bold, modifier = Modifier.clickable(onClick = onRequestAccessClick) ) } Spacer(modifier = Modifier.height(16.dp)) } } }
@Composable private fun SectionLabel(text: String, color: Color) { Text( text = text, color = color, style = AppTextStyles.sectionLabel ) }
@Composable private fun RoleButton( title: String, isSelected: Boolean, icon: @Composable () -> Unit, onClick: () -> Unit, modifier: Modifier, primaryBlue: Color ) { val background = Color(0xFFF3F4F6)
Box( modifier = modifier .height(110.dp) .background(background, RoundedCornerShape(20.dp)) .clickable(onClick = onClick) .padding(16.dp) ) { RadioButton( selected = isSelected, onClick = onClick, modifier = Modifier .align(Alignment.TopEnd) .offset(x = 8.dp, y = (-8).dp) .size(24.dp), colors = RadioButtonDefaults.colors( selectedColor = primaryBlue, unselectedColor = Color(0xFF9CA3AF) ) )
Column( modifier = Modifier.fillMaxSize(), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { icon() Spacer(modifier = Modifier.height(8.dp)) Text( text = title, fontSize = 14.sp, fontWeight = FontWeight.Bold, color = primaryBlue ) } } }
@Composable private fun InputField( value: String, onValueChange: (String) -> Unit, placeholder: String, leadingIcon: @Composable () -> Unit, keyboardType: KeyboardType, visualTransformation: VisualTransformation?, trailingIcon: @Composable (() -> Unit)? = null, background: Color ) { OutlinedTextField( value = value, onValueChange = onValueChange, singleLine = true, modifier = Modifier .fillMaxWidth() .height(60.dp), textStyle = MaterialTheme.typography.bodyLarge.copy( fontSize = AppTextStyles.fieldText.fontSize, lineHeight = AppTextStyles.fieldText.lineHeight, fontWeight = AppTextStyles.fieldText.fontWeight ), placeholder = { Text( text = placeholder, color = Color(0xFF8E95A3), style = AppTextStyles.fieldText ) }, leadingIcon = leadingIcon, trailingIcon = trailingIcon, keyboardOptions = KeyboardOptions(keyboardType = keyboardType), visualTransformation = visualTransformation ?: VisualTransformation.None, colors = OutlinedTextFieldDefaults.colors( focusedContainerColor = background, unfocusedContainerColor = background, disabledContainerColor = background, focusedTextColor = Color(0xFF111827), unfocusedTextColor = Color(0xFF111827), disabledTextColor = Color(0xFF6B7280), cursorColor = Color(0xFF0D5CAB), focusedBorderColor = Color.Transparent, unfocusedBorderColor = Color.Transparent ), shape = RoundedCornerShape(14.dp) ) }
